const crypto = require('crypto');

const SALT_LENGTH = 32;
const KEY_LENGTH = 64;
const ITERATIONS = 100000;
const DIGEST = 'sha512';

function generateSalt() {
  return crypto.randomBytes(SALT_LENGTH).toString('hex');
}

function hashPassword(password) {
  return new Promise((resolve, reject) => {
    const salt = generateSalt();
    crypto.pbkdf2(password, salt, ITERATIONS, KEY_LENGTH, DIGEST, (err, derivedKey) => {
      if (err) return reject(err);
      const hash = derivedKey.toString('hex');
      resolve({
        hash,
        salt,
        iterations: ITERATIONS,
        keyLength: KEY_LENGTH,
        digest: DIGEST,
        combined: `${DIGEST}:${ITERATIONS}:${KEY_LENGTH}:${salt}:${hash}`
      });
    });
  });
}

function verifyPassword(password, storedCombined) {
  return new Promise((resolve, reject) => {
    const parts = storedCombined.split(':');
    if (parts.length !== 5) {
      return reject(new Error('Invalid stored hash format'));
    }

    const [digest, iterations, keyLength, salt, storedHash] = parts;
    const iterationsNum = parseInt(iterations, 10);
    const keyLengthNum = parseInt(keyLength, 10);

    crypto.pbkdf2(password, salt, iterationsNum, keyLengthNum, digest, (err, derivedKey) => {
      if (err) return reject(err);
      const hash = derivedKey.toString('hex');
      const isMatch = crypto.timingSafeEqual(
        Buffer.from(hash, 'hex'),
        Buffer.from(storedHash, 'hex')
      );
      resolve(isMatch);
    });
  });
}

// --- Simple in-memory user store for prototype ---
const users = new Map();

async function registerUser(username, password) {
  if (!username || !password) {
    throw new Error('Username and password are required');
  }

  if (typeof password !== 'string' || password.length < 8) {
    throw new Error('Password must be at least 8 characters long');
  }

  const normalizedUsername = username.trim().toLowerCase();

  if (users.has(normalizedUsername)) {
    throw new Error('Username already exists');
  }

  const { combined } = await hashPassword(password);

  users.set(normalizedUsername, {
    username: normalizedUsername,
    passwordHash: combined,
    createdAt: new Date().toISOString()
  });

  return { username: normalizedUsername, message: 'User registered successfully' };
}

async function authenticateUser(username, password) {
  if (!username || !password) {
    throw new Error('Username and password are required');
  }

  const normalizedUsername = username.trim().toLowerCase();
  const user = users.get(normalizedUsername);

  if (!user) {
    // Still hash to prevent timing attacks that reveal user existence
    await hashPassword(password);
    return { success: false, message: 'Invalid username or password' };
  }

  const isValid = await verifyPassword(password, user.passwordHash);

  if (!isValid) {
    return { success: false, message: 'Invalid username or password' };
  }

  return { success: true, message: 'Authentication successful', username: normalizedUsername };
}

